import{_ as t,p as s,q as e,a1 as a}from"./framework-5866ffd3.js";const n={},d=a(`<h1 id="systemctl" tabindex="-1"><a class="header-anchor" href="#systemctl" aria-hidden="true">#</a> systemctl</h1><p>系统服务管理器指令</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p><strong>systemctl命令</strong> 是系统服务管理器指令，它实际上将 service 和 chkconfig 这两个命令组合到一起。</p><table><thead><tr><th>任务</th><th>旧指令</th><th>新指令</th></tr></thead><tbody><tr><td>使某服务自动启动</td><td>chkconfig --level 3 httpd on</td><td>systemctl enable httpd.service</td></tr><tr><td>使某服务不自动启动</td><td>chkconfig --level 3 httpd off</td><td>systemctl disable httpd.service</td></tr><tr><td>检查服务状态</td><td>service httpd status</td><td>systemctl status httpd.service （服务详细信息） systemctl is-active httpd.service （仅显示是否 Active)</td></tr><tr><td>显示所有已启动的服务</td><td>chkconfig --list</td><td>systemctl list-units --type=service</td></tr><tr><td>启动服务</td><td>service httpd start</td><td>systemctl start httpd.service</td></tr><tr><td>停止服务</td><td>service httpd stop</td><td>systemctl stop httpd.service</td></tr><tr><td>重启服务</td><td>service httpd restart</td><td>systemctl restart httpd.service</td></tr><tr><td>重载服务</td><td>service httpd reload</td><td>systemctl reload httpd.service</td></tr></tbody></table><h3 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>systemctl start nfs-server.service <span class="token builtin class-name">.</span> <span class="token comment"># 启动nfs服务</span>
systemctl <span class="token builtin class-name">enable</span> nfs-server.service <span class="token comment"># 设置开机自启动</span>
systemctl disable nfs-server.service <span class="token comment"># 停止开机自启动</span>
systemctl status nfs-server.service <span class="token comment"># 查看服务当前状态</span>
systemctl restart nfs-server.service <span class="token comment"># 重新启动某服务</span>
systemctl list-units <span class="token parameter variable">--type</span><span class="token operator">=</span>service <span class="token comment"># 查看所有已启动的服务</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>开启防火墙22端口</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>iptables <span class="token parameter variable">-I</span> INPUT <span class="token parameter variable">-p</span> tcp <span class="token parameter variable">--dport</span> <span class="token number">22</span> <span class="token parameter variable">-j</span> accept
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如果仍然有问题，就可能是SELinux导致的</p><p>关闭SElinux：</p><p>修改<code>/etc/selinux/config</code>文件中的<code>SELINUX=&quot;&quot;</code>为disabled，然后重启。</p><p>彻底关闭防火墙：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> systemctl status firewalld.service
<span class="token function">sudo</span> systemctl stop firewalld.service          
<span class="token function">sudo</span> systemctl disable firewalld.service
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,14),c=[d];function r(i,l){return s(),e("div",null,c)}const o=t(n,[["render",r],["__file","systemctl.html.vue"]]);export{o as default};
